import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function AddNew({ employee }) {
  const navigate = useNavigate();

  const [activeTab, setActiveTab] = useState("travel");

  // Travel inputs
  const [travel, setTravel] = useState({
    date: "",
    amount: "",
    from: "",
    to: "",
    purpose: ""
  });

  // Ticket inputs
  const [ticket, setTicket] = useState({
    date: "",
    amount: "",
    assigned_to: "",
    purpose: ""
  });

  const handleTravelSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await fetch(`${apiBase}/add-travel`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          empld: employee.empld,
          travel_date: travel.date,
          amount: travel.amount,
          location_from: travel.from,
          location_to: travel.to,
          purpose: travel.purpose
        })
      });

      setTravel({ date: "", amount: "", from: "", to: "", purpose: "" });
      alert("Travel expense added!");
    } catch (err) {
      alert("Error adding travel");
    }
  };

  const handleTicketSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await fetch(`${apiBase}/add-ticket`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          empld: employee.empld,
          ticket_date: ticket.date,
          amount: ticket.amount,
          assigned_to: ticket.assigned_to,
          purpose: ticket.purpose
        })
      });

      setTicket({ date: "", amount: "", assigned_to: "", purpose: "" });
      alert("Ticket expense added!");
    } catch (err) {
      alert("Error adding ticket");
    }
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 16,
        fontFamily: "Segoe UI"
      }}
    >
      <div
        style={{
          maxWidth: 900,
          margin: "0 auto",
          background: "#ffffff",
          borderRadius: 16,
          padding: 18,
          boxShadow: "0 6px 20px rgba(0,0,0,0.12)"
        }}
      >
        {/* Back Arrow */}
        <button
          onClick={() => navigate("/profile")}
          style={{
            background: "transparent",
            border: "none",
            color: green,
            fontSize: 16,
            cursor: "pointer",
            marginBottom: 10
          }}
        >
          ⬅ Back
        </button>

        <h2 style={{ color: green, marginTop: 0 }}>Add New Expense</h2>

        {/* Tabs */}
        <div style={{ display: "flex", gap: 10, marginTop: 10 }}>
          <button
            onClick={() => setActiveTab("travel")}
            style={{
              padding: 10,
              background: activeTab === "travel" ? green : "#ddd",
              color: activeTab === "travel" ? "#fff" : "#000",
              borderRadius: 8,
              border: "none",
              cursor: "pointer"
            }}
          >
            Travel Expense
          </button>

          <button
            onClick={() => setActiveTab("ticket")}
            style={{
              padding: 10,
              background: activeTab === "ticket" ? green : "#ddd",
              color: activeTab === "ticket" ? "#fff" : "#000",
              borderRadius: 8,
              border: "none",
              cursor: "pointer"
            }}
          >
            Ticket Expense
          </button>
        </div>

        {/* Travel Form */}
        {activeTab === "travel" && (
          <form onSubmit={handleTravelSubmit} style={{ marginTop: 20 }}>
            <label>Date</label>
            <input
              type="date"
              value={travel.date}
              onChange={(e) =>
                setTravel({ ...travel, date: e.target.value })
              }
              required
            />

            <label>Amount</label>
            <input
              type="number"
              value={travel.amount}
              onChange={(e) =>
                setTravel({ ...travel, amount: e.target.value })
              }
              required
            />

            <label>From</label>
            <input
              type="text"
              value={travel.from}
              onChange={(e) =>
                setTravel({ ...travel, from: e.target.value })
              }
              required
            />

            <label>To</label>
            <input
              type="text"
              value={travel.to}
              onChange={(e) =>
                setTravel({ ...travel, to: e.target.value })
              }
              required
            />

            <label>Purpose</label>
            <input
              type="text"
              value={travel.purpose}
              onChange={(e) =>
                setTravel({ ...travel, purpose: e.target.value })
              }
            />

            <button type="submit" style={buttonStyle()}>
              Add Travel Expense
            </button>
          </form>
        )}

        {/* Ticket Form */}
        {activeTab === "ticket" && (
          <form onSubmit={handleTicketSubmit} style={{ marginTop: 20 }}>
            <label>Date</label>
            <input
              type="date"
              value={ticket.date}
              onChange={(e) =>
                setTicket({ ...ticket, date: e.target.value })
              }
              required
            />

            <label>Amount</label>
            <input
              type="number"
              value={ticket.amount}
              onChange={(e) =>
                setTicket({ ...ticket, amount: e.target.value })
              }
              required
            />

            <label>Assigned To</label>
            <input
              type="text"
              value={ticket.assigned_to}
              onChange={(e) =>
                setTicket({ ...ticket, assigned_to: e.target.value })
              }
            />

            <label>Purpose</label>
            <input
              type="text"
              value={ticket.purpose}
              onChange={(e) =>
                setTicket({ ...ticket, purpose: e.target.value })
              }
            />

            <button type="submit" style={buttonStyle()}>
              Add Ticket Expense
            </button>
          </form>
        )}
      </div>
    </div>
  );
}

function buttonStyle() {
  return {
    marginTop: 12,
    padding: 10,
    borderRadius: 8,
    background: green,
    color: "#fff",
    border: "none",
    cursor: "pointer",
    width: "100%",
    fontWeight: 600
  };
}
